import{_ as t,o,c as a,a2 as d}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"ECodex 1.0.2 发布说明","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes/1.0.2.md","filePath":"release-notes/1.0.2.md","lastUpdated":1781676644000}'),l={name:"release-notes/1.0.2.md"};function r(i,e,s,n,c,h){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="ecodex-1-0-2-发布说明" tabindex="-1">ECodex 1.0.2 发布说明 <a class="header-anchor" href="#ecodex-1-0-2-发布说明" aria-label="Permalink to &quot;ECodex 1.0.2 发布说明&quot;">​</a></h1><p>ECodex 1.0.2 聚焦“常驻后台工作台”和“AI 开发复盘证据”。这个版本让终端在关闭窗口后更适合长期运行，强化命令完成 / 失败提醒，并补齐 Session Vault 的失败 loop 预览能力。</p><h2 id="推荐下载" tabindex="-1">推荐下载 <a class="header-anchor" href="#推荐下载" aria-label="Permalink to &quot;推荐下载&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产物</th><th>适用场景</th><th>说明</th></tr></thead><tbody><tr><td><code>ecodex-win-x64-sc</code></td><td>大多数 Windows 10/11 用户</td><td>self-contained app 目录，不需要共享 .NET runtime。</td></tr><tr><td><code>ecodex-cli-win-x64</code></td><td>自动化脚本和 CI</td><td>仅命令行包，提供 <code>ecodex</code> 命令。</td></tr><tr><td>Inno Setup 安装器</td><td>传统桌面安装</td><td>简体中文安装 / 卸载界面，创建快捷方式，卸载保留 <code>%USERPROFILE%\\.ecodex</code>。</td></tr><tr><td>MSIX 包</td><td>企业分发</td><td>适合受管环境。</td></tr></tbody></table><p>详细步骤见 <a href="./../installation">安装</a>。</p><h2 id="新特性" tabindex="-1">新特性 <a class="header-anchor" href="#新特性" aria-label="Permalink to &quot;新特性&quot;">​</a></h2><ul><li><strong>托盘常驻</strong>：关闭按钮或最小化会隐藏到系统托盘，后台终端和通知继续工作；托盘菜单可选择保留或终止后台终端。</li><li><strong>低噪声通知</strong>：PowerShell hook 能携带 workspace / surface / pane 上下文，后台命令完成、失败或 Codex 等待输入时进入未读中心，并支持 Toast 点击跳转。</li><li><strong>默认 skills 种子</strong>：App 启动时从安装目录 <code>default-skills</code> 安全复制到 <code>%USERPROFILE%\\.agents\\skills</code>，同名目录跳过，不覆盖用户已有 skill。</li><li><strong>多行输入</strong>：所有 ECodex Terminal 默认支持 <code>Ctrl+Enter</code> 输入换行，普通 <code>Enter</code> 仍提交命令。</li><li><strong>失败 loop 预览</strong>：Session Vault 可以从 terminal transcript 生成可复制的失败命令、transcript 和诊断证据预览。</li><li><strong>AgentConversation recorder seam</strong>：Core 层新增 runtime recorder seam，为后续把 Agent 消息写入可复盘证据包打基础；当前不接真实 LLM 或 UI。</li></ul><h2 id="运维与维护者改进" tabindex="-1">运维与维护者改进 <a class="header-anchor" href="#运维与维护者改进" aria-label="Permalink to &quot;运维与维护者改进&quot;">​</a></h2><ul><li>新增 <code>.ecodex/ecodex.example.json</code> dogfood 示例，覆盖本仓 build、unit test、docs build、status 和 health 命令。</li><li>新增 <code>scripts/smoke-ecodex-v2.ps1</code>，用于手动验证 status、workspace、pane 与 browser 最小闭环。</li><li>新增 <code>scripts/smoke-toast-activation.ps1</code>，用于记录 Toast 展示、点击恢复、pane 聚焦和 Codex 等待输入提醒证据。</li><li>新增 <code>scripts/release-evidence.ps1</code>，用于汇总发布前 build、test、docs、perf、doctor 和 release workflow 证据路径。</li><li>PR 模板新增可选 Handoff 区块，便于 Agent 中断或交接时记录验证、风险、下一步和回滚点。</li></ul><h2 id="升级注意事项" tabindex="-1">升级注意事项 <a class="header-anchor" href="#升级注意事项" aria-label="Permalink to &quot;升级注意事项&quot;">​</a></h2><ul><li>替换文件前建议停止 <code>ecodex-app.exe</code>、<code>ecodex-daemon.exe</code> 和旧终端会话，避免 Windows 文件锁。</li><li>安装后运行 <code>ecodex doctor</code> 和 <code>ecodex setup status</code> 检查 PATH、daemon、WebView2、PowerShell hook 与配置目录。</li><li>卸载与更新默认保留 <code>%USERPROFILE%\\.ecodex</code>，不会删除现有 session、resume、command log 或用户 skills。</li><li>Session Vault 的 Agent 消息区在真实 Agent runtime 接线前可能为空；当前失败 loop 预览仍以命令日志、transcript 和诊断证据为主。</li></ul><h2 id="发布门槛" tabindex="-1">发布门槛 <a class="header-anchor" href="#发布门槛" aria-label="Permalink to &quot;发布门槛&quot;">​</a></h2><ul><li>发布前仍按 P0 = 0、P1 &lt;= 3 且 P1 必须有 workaround 的门槛验收。</li><li>如果安装、Toast、WebView2 或 ConPTY 行为异常，优先参考 <a href="./../troubleshooting">故障排查</a> 和 <a href="./../release-readiness">发布就绪</a>。</li></ul><h2 id="更多文档" tabindex="-1">更多文档 <a class="header-anchor" href="#更多文档" aria-label="Permalink to &quot;更多文档&quot;">​</a></h2><ul><li><a href="./../installation">安装</a></li><li><a href="./../getting-started">快速上手</a></li><li><a href="./../cli">命令行</a></li><li><a href="./../session-restore">会话恢复</a></li><li><a href="./../troubleshooting">故障排查</a></li></ul>',15)])])}const x=t(l,[["render",r]]);export{p as __pageData,x as default};
